    def solve(n: Long, m: Long, sources: Array[Array[Long]]): Array[Array[Long]] = {
        val N = n.toInt
        val M = m.toInt

        // T[r][c]: Minimum time to reach (r, c)
        val T = Array.fill(N) { Array.fill(M)(Long.MaxValue) }
        // C[r][c]: Color at time T[r][c]
