class MinPriorityQueue {
    constructor() {
        // Heap stores elements: [time, r, c, color]
        this.heap = [];
    }

    isEmpty() {
        return this.heap.length === 0;
    }

    getParentIndex(i) { return Math.floor((i - 1) / 2); }
    getLeftChildIndex(i) { return 2 * i + 1; }
    getRightChildIndex(i) { return 2 * i + 2; }

    swap(i, j) {
        [this.heap[i], this.heap[j]] = [this.heap[j], this.heap[i]];
    }

    // Compares based on time (index 0). Lower time has higher priority.
    compare(a, b) {
        return a[0] < b[0];
    }

    push(element) {
        this.heap.push(element);
        this.bubbleUp(this.heap.length - 1);
    }

    bubbleUp(index) {
        let currentIndex = index;
        while (currentIndex > 0) {
            const parentIndex = this.getParentIndex(currentIndex);
            if (this.compare(this.heap[currentIndex], this.heap[parentIndex])) {
                this.swap(currentIndex, parentIndex);
                currentIndex = parentIndex;
            } else {
                break;
            }
        }
    }

    pop() {
        if (this.isEmpty()) return null;
        if (this.heap.length === 1) return this.heap.pop();

        const top = this.heap[0];
        this.heap[0] = this.heap.pop();
        this.bubbleDown(0);
        return top;
    }

    bubbleDown(index) {
        let currentIndex = index;
        const lastIndex = this.heap.length - 1;

        while (true) {
            let left = this.getLeftChildIndex(currentIndex);
            let right = this.getRightChildIndex(currentIndex);
            let smallest = currentIndex;

            // Check left child
            if (left <= lastIndex && this.compare(this.heap[left], this.heap[smallest])) {
                smallest = left;
            }

            // Check right child
            if (right <= lastIndex && this.compare(this.heap[right], this.heap[smallest])) {
                smallest = right;
            }

            if (smallest !== currentIndex) {
                this.swap(currentIndex, smallest);
                currentIndex = smallest;
            } else {
                break;
            }
        }
    }
}

function solve(n, m, sources) {
    const INF = Number.MAX_SAFE_INTEGER;

    const dist = Array(n).fill(0).map(() => Array(m).fill(INF));
    const colors = Array(n).fill(0).map(() => Array(m).fill(0));

    const pq = new MinPriorityQueue();

    // 1. Initialization from sources
    for (const source of sources) {
        const r = source[0];
        const c = source[1];
        const color = source[2];

        dist[r][c] = 0;
        colors[r][c] = color;

        // PQ stores: [time, r, c, color]
        pq.push([0, r, c, color]);
    }

    const DR = [-1, 1, 0, 0];
    const DC = [0, 0, -1, 1];

    // 2. BFS/Dijkstra Loop
    while (!pq.isEmpty()) {
        const [t, r, c, c_src] = pq.pop();

        // Optimization checks for stale entries

        // If we found a strictly faster path already, ignore this outdated entry.
        if (t > dist[r][c]) {
            continue;
        }

        // If we arrived at the same time t, but the stored color is already higher, ignore.
        if (t === dist[r][c] && c_src < colors[r][c]) {
            continue;
        }

        // Explore neighbors
        const t_next = t + 1;

        for (let i = 0; i < 4; i++) {
            const r_next = r + DR[i];
            const c_next = c + DC[i];

            if (r_next >= 0 && r_next < n && c_next >= 0 && c_next < m) {

                const D_old = dist[r_next][c_next];
                const C_old = colors[r_next][c_next];
                const c_next_color = c_src;

                if (t_next < D_old) {
                    // Case 1: Strictly faster arrival time. Update everything and enqueue.
                    dist[r_next][c_next] = t_next;
                    colors[r_next][c_next] = c_next_color;
                    pq.push([t_next, r_next, c_next, c_next_color]);

                } else if (t_next === D_old) {
                    // Case 2: Tie in arrival time. Check color dominance.
                    if (c_next_color > C_old) {
                        // Higher color wins the tie. Update color and re-enqueue 
                        // to propagate the superior color.
                        colors[r_next][c_next] = c_next_color;

                        // Re-enqueueing ensures that future expansion from (r_next, c_next) 
                        // uses the new, higher color c_next_color.
                        pq.push([t_next, r_next, c_next, c_next_color]);
                    }
