object GridColoring {
  // Helper class/case class for PQ state
  case class State(time: Long, r: Long, c: Long, color: Long)

  def solve(n: Long, m: Long, sources: Array[Array[Long]]): Array[Array[Long]] = {
    // T_min[r][c]: Minimum time to reach (r, c)
    val tMin = Array.fill(n.toInt) { Array.fill(m.toInt) { Long.MaxValue } }
    // C_final[r][c]: Final color of (r, c) achieved at T_min
    val cFinal = Array.fill(n.toInt) { Array.fill(m.toInt) { 0L } }

    // Priority Queue: Min-heap based on time (Ascending), then color (Descending)
    val pq = new PriorityQueue[State] {
      override def compare(a: State, b: State): Int = {
        // Primary sorting: Time (Ascending)
        if (a.time != b.time) {
          a.time.compareTo(b.time)
        } else {
          // Secondary sorting: Color (Descending) - prioritize higher colors at same time step
          b.color.compareTo(a.color)
        }
      }
    }

    // 1. Initialization with sources
    for (source in sources) {
      val r = source(0)
      val c = source(1)
      val color = source(2)

      if (tMin(r.toInt)(c.toInt) > 0) { // Should only happen for initial setup
        tMin(r.toInt)(c.toInt) = 0L
        cFinal(r.toInt)(c.toInt) = color
        pq.add(State(0L, r, c, color))
      }
    }

    // Directions: Up, Down, Left, Right
    val dr = Array(-1L, 1L, 0L, 0L)
    val dc = Array(0L, 0L, -1L, 1L)

    // 2. BFS/Dijkstra processing
    while (pq.nonEmpty) {
      val current = pq.poll()
      val t = current.time
      val r = current.r
      val c = current.c
      val currentColor = current.color

      val rInt = r.toInt
      val cInt = c.toInt

      // Optimization: Check if this extracted state is stale
      // It is stale if we already found a path to (r, c) that is strictly better (faster time or same time but higher color)
      if (t > tMin(rInt)(cInt)) continue
      if (t == tMin(rInt)(cInt) && currentColor < cFinal(rInt)(cInt)) continue

      // Explore neighbors
      for (i <- 0 until 4) {
        val nr = r + dr(i)
        val nc = c + dc(i)

        // Check boundaries
        if (nr >= 0L && nr < n && nc >= 0L && nc < m) {
          val nextT = t + 1L
          val nrInt = nr.toInt
          val ncInt = nc.toInt

          // Case 1: Found a strictly faster path
          if (nextT < tMin(nrInt)(ncInt)) {
            tMin(nrInt)(ncInt) = nextT
            cFinal(nrInt)(ncInt) = currentColor
            pq.add(State(nextT, nr, nc, currentColor))
          } 
          // Case 2: Found a path of equal minimum time
          else if (nextT == tMin(nrInt)(ncInt)) {
            // Conflict resolution: take maximum color
            if (currentColor > cFinal(nrInt)(ncInt)) {
              cFinal(nrInt)(ncInt) = currentColor
              // If we improve the color at the existing minimum time, we must propagate this stronger color forward
              pq.add(State(nextT, nr, nc, currentColor))
            }
          }
        }
      }
    }

    // 3. Return final state
    cFinal
  }
}
