import scala.collection.mutable

object Solution {
  // Define the required signature structure
  def n(N: Long): Array[Array[Long]], def m(M: Long): Array[Array[Long]], def sources(Array[Array[Long]]): Array[Array[Long]] = {

    // Since N*M <= 10^5, we can safely use Int for array dimensions and indices.
    val nInt = N.toInt
    val mInt = M.toInt
    val maxTime = N * M + 1

    // D[r][c]: Minimum time step to reach (r, c). Initialize to maxTime (infinity).
    val D = Array.fill(nInt) { Array.fill(mInt) { maxTime } }

    // C[r][c]: Final color of (r, c). Initialize to 0.
    val C = Array.fill(nInt) { Array.fill(mInt) { 0L } }

    // Queue for cells finalized at current time step t
    // Stores coordinates (r, c)
    var currentLayer = mutable.Queue.empty[Tuple2[Int, Int]]

    // Initialization using sources
    for (source in sources) {
      val r = source(0).toInt
      val c = source(1).toInt
      val color = source(2)

      // Sources are at time t=0
      if (r < nInt && c < mInt) {
        D(r)(c) = 0L
        C(r)(c) = color
        currentLayer.enqueue((r, c))
      }
    }

    // Directions: (dr, dc)
    val directions = Array((0, 1), (0, -1), (1, 0), (-1, 0))

    // Layer-by-layer BFS
    while (currentLayer.nonEmpty) {

      // Q_next will store cells reached for the first time in the next time step (t+1)
      var nextLayer = mutable.Queue.empty[Tuple2[Int, Int]]

      // Updates stores for cells reached in the next step: (r, c) -> Set of incoming colors
      // We use a mutable map to collect all simultaneous arrivals for a given cell
      val updates = mutable.Map[(Int, Int), mutable.Set[Long]]()

      // 1. Propagation step: Determine potential arrivals at t+1
      var nextTime = D(currentLayer.dequeue()._1)(currentLayer.dequeue()._2) + 1 // This line is flawed if we dequeue multiple times in a loop

      // To correctly get the time t of the current layer, we iterate over the layer size
      val layerSize = currentLayer.size
      var t = -1
      if (layerSize > 0) {
          // Peek at the first element to determine time t
          val sample = currentLayer.head
          t = D(sample._1)(sample._2).toInt
      }

      // Process all cells in the current layer (time t)
      for (i <- 0 until layerSize) {
        val (r, c) = currentLayer.dequeue()
        val colorSource = C(r)(c)

        // Explore neighbors
        for ((dr, dc) <- directions) {
          val nr = r + dr
          val nc = c + dc

          // Check bounds
          if (nr >= 0 && nr < nInt && nc >= 0 && nc < mInt) {

            // Only propagate to previously UNCOLORED cells (D[nr][nc] == maxTime)
            if (D(nr)(nc) == maxTime) {
              val targetCoord = (nr, nc)

              // Record that this color arrives at (nr, nc) at time t+1
              updates.getOrElseUpdate(targetCoord, mutable.Set.empty[Long]).add(colorSource)

              // Add to the next layer queue
              nextLayer.enqueue(targetCoord)
            }
          }
        }
      }

      // 2. Finalization step: Update D and C for cells in the next layer (time t+1)
      for ((coord, colors) <- updates) {
        val (nr, nc) = coord

        // Since we only collected updates for cells where D was maxTime, this is the first arrival time.
        D(nr)(nc) = (t + 1).toLong

        // Assign the maximum incoming color
        var maxColor = 0L
        for (color <- colors) {
          if (color > maxColor) {
            maxColor = color
          }
        }
        C(nr)(nc) = maxColor
      }

      // Move to the next layer
      currentLayer = nextLayer
    }

    C // Return the final color grid
  }
}
