import scala.collection.mutable

def solve(n: Long, m: Long, sources: Array[Array[Long]]): Array[Array[Long]] = {
    val N = n.toInt
    val M = m.toInt

    // Initialize the final color grid (0 means uncolored)
    val finalColor = Array.ofDim[Long](N, M)

    // Queue for the current time step T (cells colored at time T)
    var currentLayer = mutable.Seq[(Int, Int)]()

    // Initialize sources
    for (source in sources) {
        val r = source(0).toInt
        val c = source(1).toInt
        val color = source(2)

        // Sources are already colored at time T=0
        finalColor(r)(c) = color
        currentLayer += (r, c)
    }

    // Directions: Up, Down, Left, Right
    val dr = Array(0, 0, 1, -1)
    val dc = Array(1, -1, 0, 0)

    var T = 0L

    while (currentLayer.nonEmpty) {
        var nextLayer = mutable.Seq[(Int, Int)]()

        // Map: (r', c') -> List of incoming colors at time T+1
        val candidates = mutable.HashMap[(Int, Int), mutable.List[Long]]()

        // Step 1: Propagate colors from currentLayer (Time T)
        for ((r, c) <- currentLayer) {
            val currentColor = finalColor(r)(c)

            // Check neighbors
            for (i <- 0 until 4) {
                val nr = r + dr(i)
                val nc = c + dc(i)

                // Check boundaries
                if (nr >= 0 && nr < N && nc >= 0 && nc < M) {
                    // Only propagate to UNCOLORED cells
                    if (finalColor(nr)(nc) == 0) {
                        val coord = (nr, nc)

                        // Add the current color as a potential arrival color
                        candidates.getOrElseUpdate(coord, mutable.List[Long]()).+= (currentColor)
                    }
                }
            }
        }

        // Step 2: Process candidates to determine final color for Time T+1
        for ((coord, incomingColors) <- candidates) {
            val (r_next, c_next) = coord

            // Re-check if the cell is still uncolored (it might have been reached 
            // by another source in a previous layer iteration if the logic was flawed, 
            // but here, since we only added candidates that were 0, it must be 0)
            if (finalColor(r_next)(c_next) == 0) {
                // Determine the final color: maximum color value
                var maxColor = 0L
                for (color <- incomingColors) {
                    if (color > maxColor) {
                        maxColor = color
                    }
                }

                // Update grid state
                finalColor(r_next)(c_next) = maxColor

                // Add to the next layer queue
                nextLayer += coord
            }
        }

        currentLayer = nextLayer
        T += 1
    }

    finalColor
}

